{
  "name": "open-generative-ai",
  "description": "Open-source alternative to HF AI — AI image, video, cinema and lip sync studio",
  "homepage": "https://github.com/Anil-matcha/Open-Generative-AI",
  "private": true,
  "version": "2.0.0",
  "license": "MIT",
  "workspaces": [
    "packages/studio",
    "packages/Vibe-Workflow/packages/workflow-builder",
    "packages/Open-Poe-AI/packages/agents",
    "packages/Open-AI-Design-Agent/packages/design-agent"
  ],
  "scripts": {
    "dev": "next dev",
    "build": "next build",
    "start": "next start",
    "lint": "next lint",
    "build:studio": "npm run build -w studio",
    "build:workflow": "npm run build -w workflow-builder",
    "build:agent": "npm run build -w ai-agent",
    "build:design": "npm run build -w design-agent",
    "build:packages": "npm run build:workflow && npm run build:agent && npm run build:design && npm run build:studio",
    "setup": "git submodule update --init --recursive && npm install && npm run build:packages",
    "vite:dev": "vite",
    "vite:build": "vite build",
    "electron:dev": "npm run vite:build && electron .",
    "electron:build": "vite build && electron-builder --mac",
    "electron:build:win": "vite build && electron-builder --win",
    "electron:build:linux": "vite build && electron-builder --linux",
    "electron:build:linux:dir": "vite build && electron-builder --linux dir",
    "electron:build:linux:arm64:dir": "vite build && electron-builder --linux dir --arm64",
    "stage:local-ai": "node scripts/stage-local-ai-binary.js",
    "package:linux:deb": "node scripts/package-linux-deb.js",
    "package:linux:deb:arm64": "node scripts/package-linux-deb.js --arch arm64",
    "package:linux:deb:x64": "node scripts/package-linux-deb.js --arch x64",
    "electron:build:all": "vite build && electron-builder --mac --win --linux"
  },
  "build": {
    "appId": "ai.generative.open",
    "productName": "Open Generative AI",
    "copyright": "Copyright © 2025",
    "directories": {
      "output": "release"
    },
    "afterPack": "./afterPack.js",
    "files": [
      "dist/**/*",
      "electron/**/*"
    ],
    "extraResources": [
      {
        "from": "build/local-ai",
        "to": "local-ai",
        "filter": [
          "**/*"
        ]
      }
    ],
    "mac": {
      "category": "public.app-category.graphics-design",
      "icon": "public/banner.png",
      "gatekeeperAssess": false,
      "target": [
        {
          "target": "dmg",
          "arch": [
            "x64",
            "arm64"
          ]
        }
      ]
    },
    "win": {
      "icon": "public/banner.png",
      "signAndEditExecutable": false,
      "target": [
        {
          "target": "nsis",
          "arch": [
            "x64"
          ]
        }
      ]
    },
    "nsis": {
      "oneClick": false,
      "allowToChangeInstallationDirectory": true,
      "include": "build/installer.nsh"
    },
    "linux": {
      "icon": "public/banner.png",
      "category": "Utility",
      "maintainer": "Open Generative AI Team",
      "extraFiles": [
        {
          "from": "build/linux/apparmor.profile",
          "to": "resources/apparmor.profile"
        }
      ],
      "target": [
        {
          "target": "AppImage",
          "arch": [
            "x64"
          ]
        },
        {
          "target": "deb",
          "arch": [
            "x64"
          ]
        }
      ]
    }
  },
  "dependencies": {
    "axios": "^1.7.0",
    "next": "^15.0.0",
    "react": "^19.0.0",
    "react-dom": "^19.0.0",
    "react-hot-toast": "^2.4.1",
    "studio": "*",
    "workflow-builder": "file:./packages/Vibe-Workflow/packages/workflow-builder",
    "ai-agent": "file:./packages/Open-Poe-AI/packages/agents"
  },
  "devDependencies": {
    "@eslint/eslintrc": "^3",
    "@tailwindcss/vite": "^4.1.18",
    "autoprefixer": "^10.4.24",
    "electron": "^33.4.11",
    "electron-builder": "^25.1.8",
    "eslint": "^9",
    "eslint-config-next": "^15.0.0",
    "postcss": "^8.5.6",
    "tailwindcss": "^3.4.0",
    "vite": "^5.4.0"
  },
  "main": "electron/main.js"
}

[patch.crates-io]
schemars = { git = "https://github.com/howardjohn/schemars", rev = "f3e45a59786debf49e67d6bd6d8dcffc004d39ff" }
http-serde = { git = "https://gitlab.com/howardjohn/http-serde", rev = "c2e482be0ddf029895ba72ef8749b9f94b388fc7" }
wiremock = { git = "https://github.com/howardjohn/wiremock-rs", rev = "e55f5b96083125fdabc3e62f92790ee15ae3a10d" }
rmcp = { git = "https://github.com/howardjohn/rust-sdk", rev = "7366ffc42beb89f27410ae348a67001beb4c6ba5" }

[workspace]
resolver = "2"
members = [
    "crates/agentgateway",
    "crates/agentgateway-app",
    "crates/llm",
    "crates/cel-fork/cel",
    "crates/cel-fork/cel-derive",
    "crates/celx",
    "crates/pool",
    "crates/core",
    "crates/http",
    "crates/hbone",
    "crates/protos",
    "crates/xds",
    "crates/xtask",
]
default-members = [
    "crates/agentgateway",
    "crates/agentgateway-app",
    "crates/cel-fork/cel",
    "crates/cel-fork/cel-derive",
    "crates/celx",
    "crates/pool",
    "crates/core",
    "crates/hbone",
    "crates/protos",
    "crates/xds",
]

[workspace.package]
version = "0.0.0" # We do not use this version
edition = "2024"
rust-version = "1.90"
license = "Apache-2.0"
publish = false

[workspace.dependencies]
agent-core = { path = "crates/core" }
agent-celx = { path = "crates/celx" }
agent-hbone = { path = "crates/hbone" }
agent-http = { path = "crates/http" }
agent-llm = { path = "crates/llm" }
agent-pool = { path = "crates/pool" }
agent-xds = { path = "crates/xds" }
agentgateway = { path = "crates/agentgateway" }
cel = { path = "crates/cel-fork/cel" }
cel-derive = { path = "crates/cel-fork/cel-derive" }
protos = { path = "crates/protos" }
atomic_float = { version = "1.1.0", features = ["serde"] }
anyhow = "1.0"
arc-swap = "1.9"
arcstr = { version = "1.2", features = ["serde"] }
assert_matches = "1.5.0"
async-openai = { version = "0.41", default-features = false, features = ["chat-completion-types", "moderation-types", "response-types", "realtime-types"] }
async-stream = "0.3"
async-trait = "0.1"
aws-config = { version = "1.8", default-features = false, features = ["default-https-client", "rt-tokio", "sso"] }
aws-credential-types = "1.2"
aws-sigv4 = "1.4"
aws-types = "1.3"
aws-smithy-eventstream = "0.60"
aws-smithy-types = "1.3"
aws-lc-rs = "1.17"
openssl = "0.10"
rustls-openssl = { version = "0.3", features = ["tls12"] }
axum = { version = "0.8", features = ["macros"] }
axum-core = "0.5"
axum-extra = { version = "0.12", features = ["json-lines", "typed-header"] }
multer = "3.0.0"
# Disable default features to avoid pulling in native-tls and requiring openssl
# TODO: allow default features if we ever add an openssl feature
azure_identity = { version = "1.0", default-features = false }
azure_core = { version = "1.0", default-features = false }
typespec_client_core = { default-features = false, version = "1.0" }
base64 = "0.22"
cookie = { version = "0.18", default-features = false }
bcrypt = "0.19"
bytes = { version = "1.11", features = ["serde"] }
chrono = { version = "0.4", features = ["serde"] }
clap = { version = "4.6", features = ["derive"] }
clocksource = "1.0"
crossbeam = "0.8"
divan = "0.1"
durationfmt = "0.1"
go-parse-duration = "0.1"
flurry = "0.5.2"
fs-err = { version = "3.3", features = ["tokio"] }
futures = "0.3"
futures-channel = "0.3"
futures-core = "0.3"
futures-util = "0.3"
google-cloud-auth = { git = "https://github.com/googleapis/google-cloud-rust/", rev = "58058110bf9a01074bf8e1fecf0f1d2b7ca831f4", default-features = false, features = [
    "idtoken",
    # Support the full ADC set; this one is opt in
    "gdch",
    # They use AWS-LC which is what we want so its fine. If they changed we would need to switch
    # To installing a global default which is annoying so prefer to do it this way.
    "default-rustls-provider",
] }
hashbrown = "0.17"
h2 = "0.4"
headers = "0.4"
hex = "0.4"
hickory-resolver = { version = "0.26", features = ["serde"] }
htpasswd-verify-fork = { path = "crates/htpasswd-verify-fork" }
httpdate = "1.0"
http = "1.4"
http-body = "1"
http-body-util = "0.1.3"
hyper = { version = "1.9", features = ["full"] }
hyper-rustls = "0.27"
hyper-util = { version = "0.1", features = ["full"] }
include_dir = "0.7"
indexmap = { version = "2.13", features = ["serde"] }
insta = { version = "1.47", features = ["json", "redactions", "filters", "yaml"] }
ipnet = { version = "2.12", features = ["serde"] }
itertools = "0.15"
jsonwebtoken = { version = "10.4", features = ["aws_lc_rs"] }
lazy_static = "1.5"
libc = "0.2"
notify = "8.2"
notify-debouncer-full = "0.7"
md-5 = "0.11"
num_cpus = "1.17"
once_cell = "1.21"
openapiv3 = "2.2"
opentelemetry = "0.32"
opentelemetry-http = "0.32"
opentelemetry-otlp = { version = "0.32", default-features = false, features = ["http-proto", "internal-logs", "trace", "grpc-tonic", "logs"] }
opentelemetry-proto = { version = "0.32", features = ["gen-tonic", "logs"] }
opentelemetry_sdk = { version = "0.32", features = ["rt-tokio", "logs"] }
parking_lot = "0.12"
p

{
  "name": "cloudflare-imgbed",
  "version": "2.7.5",
  "type": "module",
  "scripts": {
    "ci-test": "concurrently --kill-others \"npm start\" \"wait-on http://localhost:8080 && mocha\"",
    "ci-test:docker": "concurrently --kill-others \"npm run start:docker\" \"wait-on http://localhost:8080 && mocha\"",
    "test": "mocha",
    "start": "npx wrangler pages dev ./frontend-dist --kv \"img_url\" --r2 \"img_r2\" --ip 0.0.0.0 --port 8080 --persist-to ./data",
    "start:docker": "node --import ./deploy/server/register.mjs deploy/server/index.js",
    "deploy:worker": "node deploy/worker/generate-routes.js && npx wrangler deploy --config deploy/worker/wrangler.toml"
  },
  "dependencies": {
    "@aws-sdk/client-s3": "3.726.1",
    "@cloudflare/pages-plugin-sentry": "^1.1.3",
    "@sentry/tracing": "^7.114.0",
    "miniflare": "^4.20260708.1"
  },
  "optionalDependencies": {
    "@hono/node-server": "^1.13.8",
    "better-sqlite3": "^11.9.1",
    "hono": "^4.7.4"
  },
  "overrides": {
    "fast-xml-parser": "^5.3.6"
  },
  "devDependencies": {
    "concurrently": "^8.2.2",
    "mocha": "^8.1.3",
    "wait-on": "^7.2.0",
    "wrangler": "^4.24.0"
  }
}
